display_template.css:
.ntp {
  font-family: system-ui, -apple-system, sans-serif;
  color: #e4e4e7;
}

/* ── Status Banner ─────────────────────────────────── */
.status-banner {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: rgba(255,255,255,0.03);
  border: 1px solid rgba(255,255,255,0.06);
  border-radius: 8px;
  padding: 14px 18px;
  margin-bottom: 20px;
}
.status-left, .status-right {
  display: flex;
  align-items: center;
  gap: 16px;
}
.status-badge {
  display: inline-block;
  padding: 4px 12px;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.03em;
  background: #3f3f46;
  color: #a1a1aa;
}
.status-badge.sync-ok {
  background: rgba(34,197,94,0.15);
  color: #4ade80;
}
.status-badge.sync-warn {
  background: rgba(251,191,36,0.15);
  color: #fbbf24;
}
.status-badge.sync-fail {
  background: rgba(239,68,68,0.15);
  color: #f87171;
}
.status-detail {
  font-size: 13px;
  color: #a1a1aa;
}
.status-detail strong {
  color: #e4e4e7;
  font-weight: 500;
  font-family: ui-monospace, monospace;
}

/* ── Group ──────────────────────────────────────────── */
.group {
  margin-bottom: 20px;
}
.group-header {
  display: flex;
  align-items: center;
  gap: 12px;
  margin-bottom: 6px;
}
.group-badge {
  display: inline-flex;
  align-items: center;
  padding: 3px 10px;
  border-radius: 4px;
  font-size: 12px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}
.peer-badge {
  background: rgba(251,191,36,0.15);
  color: #fbbf24;
}
.peer-summary-inline {
  font-size: 12px;
  color: #71717a;
  display: flex;
  align-items: center;
  gap: 6px;
}
.dot {
  display: inline-block;
  width: 7px;
  height: 7px;
  border-radius: 50%;
}
.dot.green { background: #22c55e; }
.dot.red { background: #ef4444; margin-left: 8px; }

/* ── Data Table ────────────────────────────────────── */
.data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}
.data-table thead th {
  text-align: left;
  padding: 8px 12px;
  font-size: 11px;
  font-weight: 600;
  color: #71717a;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  border-bottom: 1px solid rgba(255,255,255,0.06);
}
.data-table tbody td {
  padding: 8px 12px;
  color: #d4d4d8;
  font-family: ui-monospace, monospace;
  font-size: 13px;
  border-bottom: 1px solid rgba(255,255,255,0.03);
}
.data-table tbody tr:hover {
  background: rgba(255,255,255,0.02);
}
.data-table tbody td:first-child {
  color: #a1a1aa;
  font-family: system-ui, -apple-system, sans-serif;
}
td.reach-yes {
  color: #4ade80 !important;
}
td.reach-no {
  color: #f87171 !important;
}
.empty-peers {
  padding: 12px;
  color: #71717a;
  font-size: 12px;
  font-style: italic;
}
